#include <stdio.h>
#include <math.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        double DS, DT, D;
        scanf("%lf %lf %lf", &DS, &DT, &D);
        double cand1 = D - DS - DT;
        double cand2 = fabs(DS - DT) - D;
        double ans = cand1 > cand2 ? cand1 : cand2;
        if (ans < 0) ans = 0;
        printf("%.6f\n", ans);
    }
    return 0;
}

