    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--) {
        double DS, DT, D; cin >> DS >> DT >> D;
        double cand1 = D - DS - DT;
        double cand2 = fabs(DS - DT) - D;
