code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            double DS = Double.parseDouble(st.nextToken());
            double DT = Double.parseDouble(st.nextToken());
            double D  = Double.parseDouble(st.nextToken());
            double cand1 = D - DS - DT;
            double cand2 = Math.abs(DS - DT) - D;
            double ans = Math.max(0.0, Math.max(cand1, cand2));
            sb.append(String.format(Locale.US, "%.6f", ans)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

